  const remoteJid = body?.data?.key?.remoteJid || "";                                                                                                                                                                
  if (remoteJid === "status@broadcast") {
    return [];                                                                                                                                                                                                       
  }                                                         

  if (remoteJid.includes("@g.us")) {
    return [];
  }

  // Valida conteúdo para TODOS os eventos (incoming e outcoming)                                                                                                                                                    
  const temConteudo = msg.conversation || msg.extendedTextMessage?.text ||
                      msg.audioMessage || msg.imageMessage || msg.videoMessage;                                                                                                                                      
  if (!temConteudo) {                                                                                                                                                                                                
    return [];
  }                                                                                                                                                                                                                  

  // ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━                                                                                                                                               
  // FILTRO ANTI-LOOP: descarta mensagens que sao notificacoes do proprio
  // InkFlow (handoff do bot, link de acesso pro dono, etc) chegando de                                                                                                                                              
  // volta no webhook. Evita o bot processar suas proprias notificacoes                                                                                                                                              
  // como se fossem msg do cliente.                                                                                                                                                                                  
  // ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━                                                                                                                                               
  const textoMsg = (msg.conversation || msg.extendedTextMessage?.text || msg.imageMessage?.caption || "").toString();                                                                                                
  const textoLower = textoMsg.toLowerCase();                                                                                                                                                                         
  const ehNotificacaoInterna =                                                                                                                                                                                       
    (textoLower.includes("inkflow") && textoLower.includes("handoff")) ||                                                                                                                                            
    textoLower.includes("*inkflow -") ||                                                                                                                                                                             
    textoLower.includes("a ia pausou a conversa");                                                                                                                                                                   
  if (ehNotificacaoInterna) {                                                                                                                                                                                        
    return []; // loga e dropa                              
  }                                                                                                                                                                                                                  
  // ━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

  const jid1 = body?.data?.key?.remoteJid || "";
  const jid2 = body?.data?.key?.remoteJidAlt || "";                                                                                                                                                                  
  let correctJid = "";                                                                                                                                                                                               
  if (jid1.includes("@s.whatsapp.net")) {
    correctJid = jid1;                                                                                                                                                                                               
  } else if (jid2.includes("@s.whatsapp.net")) {            
    correctJid = jid2;                                                                                                                                                                                               
  }

  const telefone = correctJid.replace("@s.whatsapp.net", "");
  const instance = body?.instance || "";
  const messageId = body?.data?.key?.id || "";

  return [{ json: { selectedNumber: correctJid, telefone: telefone, instance: instance, messageId: messageId } }];

let redis1, redis2;
try { redis1 = JSON.parse($json.Redis1 || '[]') } catch { redis1 = [$json.Redis1 || ''] }
try { redis2 = JSON.parse($json.Redis2 || '[]') } catch { redis2 = [$json.Redis2 || ''] }
const combinadoSemDuplicatas = Array.from(new Set([...redis1, ...redis2]));
const mensagem = combinadoSemDuplicatas.join(" ");
return [{ json: { mensagem_completa: mensagem } }];

return $('Aggregate2').all().map(item => {
  const conversas = item.json.conversas || [];
  if (!Array.isArray(conversas)) throw new Error("conversas não é array");
  const textoUnico = conversas.map(conversa => {
    const cliente = conversa.user_message || "sem mensagem";
    const agente = conversa.bot_message || "sem resposta";
    const dataOriginal = conversa.created_at || "Data indisponível";
    const dataFormatada = dataOriginal !== "Data indisponível" ? formatarData(dataOriginal) : dataOriginal;
    return `em: ${dataFormatada}\n\n - agente(chatbot): ${agente} \n - cliente: ${cliente}\n`;
  }).join('\n\n');
  return { json: { texto: textoUnico } };
});
function formatarData(dataString) {
  const data = new Date(dataString);
  if (isNaN(data)) return "Data inválida";
  const dia = String(data.getDate()).padStart(2, '0');
  const mes = String(data.getMonth() + 1).padStart(2, '0');
  const ano = data.getFullYear();
  const horas = String(data.getHours()).padStart(2, '0');
  const minutos = String(data.getMinutes()).padStart(2, '0');
  return `${dia}/${mes}/${ano} ${horas}:${minutos}`;
}

const output = $json.output;                                                                                                                                                                                       
  let mensagem = '';                                                                                                                                                                                                 

  // Extrai texto do output do agente — aceita vários formatos                                                                                                                                                       
  if (typeof output === 'string') {                                                                                                                                                                                  
    mensagem = output;                                                                                                                                                                                               
  } else if (output && typeof output === 'object') {                                                                                                                                                                 
    if (Array.isArray(output.messages) && output.messages.length) {                                                                                                                                                  
      mensagem = output.messages.join('\n\n');                                                                                                                                                                       
    } else if (Array.isArray(output.mensagens) && output.mensagens.length) {                                                                                                                                         
      mensagem = output.mensagens.join('\n\n');
    } else {                                                                                                                                                                                                         
      mensagem = output.mensagem || output.message || output.text || '';
    }                                                                                                                                                                                                                
  } else {                                                  
    mensagem = String(output || '');                                                                                                                                                                                 
  }                                                         

  // Se ainda vier como string JSON, tenta parsear                                                                                                                                                                   
  if (typeof mensagem === 'string' && mensagem.startsWith('{')) {
    try {                                                                                                                                                                                                            
      const parsed = JSON.parse(mensagem);                  
      if (Array.isArray(parsed.messages)) mensagem = parsed.messages.join('\n\n');                                                                                                                                   
      else if (parsed.mensagem) mensagem = parsed.mensagem;
      else if (parsed.message) mensagem = parsed.message;                                                                                                                                                            
    } catch {}                                                                                                                                                                                                       
  }                                                                                                                                                                                                                  

  const encerrar = mensagem.toLowerCase().includes('fechou!') && mensagem.toLowerCase().includes('orçamentos');                                                                                                      

  const mensagemCliente = $('Mensagem Completa').first().json.mensagem_completa || '';                                                                                                                               
  const gatilhos = ['ver trabalhos', 'portfólio', 'portfolio', 'exemplos', 'quero ver', 'tem fotos', 'mostra suas tattoos'];
  const enviar_video = gatilhos.some(g => mensagemCliente.toLowerCase().includes(g));                                                                                                                                

  const nomeAgente = $('Get a row').first().json.nome_agente;                                                                                                                                                        

  // Split por \n\n (natural, como LLM escreve) ou ||| (legado)                                                                                                                                                      
  let partes = mensagem.split(/\n{2,}/).map(s => s.trim()).filter(Boolean);
  if (partes.length === 1) {                                                                                                                                                                                         
    partes = mensagem.split('|||').map(s => s.trim()).filter(Boolean);
  }                                                                                                                                                                                                                  

  const mensagens = partes.length > 0 ? partes : [mensagem];                                                                                                                                                         

  return mensagens.map((texto, idx) => ({                                                                                                                                                                            
    json: {                                                 
      'Nome do agente': nomeAgente,                                                                                                                                                                                  
      Resposta: texto,
      encerrar: idx === mensagens.length - 1 ? encerrar : false,                                                                                                                                                     
      enviar_video: idx === 0 ? enviar_video : false,                                                                                                                                                                
      parte: idx + 1,                                                                                                                                                                                                
      total_partes: mensagens.length,                                                                                                                                                                                
    }                                                                                                                                                                                                                
  }));

